using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Check for project dependency failures
var projects = build.FindChildrenRecursive<Project>().ToList();
Console.WriteLine("=== PROJECTS ===");
foreach (var p in projects)
{
    Console.WriteLine($"  {p.Name} - Succeeded: {p.Succeeded}");
}

Console.WriteLine("\n=== SOURCE FILES (from errors) ===");
// Try to reconstruct the relevant source
var sourceFiles = build.FindChildrenRecursive<SourceFile>().ToList();
foreach (var sf in sourceFiles.Take(20))
{
    Console.WriteLine($"  {sf.Name}");
}

// Check package references
Console.WriteLine("\n=== PACKAGE REFS in Services.csproj ===");
var items = build.FindChildrenRecursive<Item>().Where(i => i.Name == "PackageReference").ToList();
foreach (var item in items)
{
    var parent = (BaseNode)item;
    string proj = "";
    while (parent != null) { if (parent is Project pp) { proj = pp.Name; break; } parent = parent.Parent as BaseNode; }
    if (proj.Contains("Services"))
        Console.WriteLine($"  {item.Text}");
}

// Also check if Api.csproj had issues
Console.WriteLine("\n=== ERRORS+WARNINGS for Api.csproj ===");
var apiErrors = build.FindChildrenRecursive<Error>().Where(e => {
    var n = (BaseNode)e;
    while (n != null) { if (n is Project pp && pp.Name.Contains("Api")) return true; n = n.Parent as BaseNode; }
    return false;
}).ToList();
Console.WriteLine($"  Error count: {apiErrors.Count}");
foreach (var e in apiErrors) Console.WriteLine($"  {e.Code}: {e.Text}");

// Check for MSB errors (project reference failures)
var msbErrors = build.FindChildrenRecursive<Error>().Where(e => e.Code != null && e.Code.StartsWith("MSB")).ToList();
Console.WriteLine($"\n=== MSB Errors: {msbErrors.Count} ===");
foreach (var e in msbErrors) Console.WriteLine($"  {e.Code}: {e.Text}");
EOF
